import React, { useState, useEffect } from 'react';
import { Menu, X, Sun, Leaf, Wind, Sparkles, ChevronRight, ArrowRight } from 'lucide-react';
import Logo from './Logo';

const Navbar: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [showLoraxMenu, setShowLoraxMenu] = useState(false);

  const toggleLoraxMenu = (e: React.MouseEvent) => {
    e.preventDefault();
    setShowLoraxMenu(!showLoraxMenu);
    setIsOpen(false);
  };

  const scrollToTop = () => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setIsOpen(false);
    setShowLoraxMenu(false);
  };

  const navLinks = [
    { name: '1000 Cranes', href: '#sadako' },
    { name: 'Cosmos', href: '#cosmos' },
  ];

  // Close menus on scroll
  useEffect(() => {
    const handleScroll = () => {
      setShowLoraxMenu(false);
      setIsOpen(false);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <>
      <nav className="fixed top-0 left-0 right-0 z-[100] bg-[#0f0a1e]/80 backdrop-blur-md border-b border-white/10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-20">
            <div 
              className="flex items-center gap-3 group cursor-pointer" 
              onClick={scrollToTop}
            >
              <Logo className="w-10 h-10 transition-all duration-300 group-hover:scale-105" />
              <span className="text-2xl font-bold tracking-tight bg-clip-text text-transparent bg-gradient-to-r from-white via-blue-100 to-white">
                Origo
              </span>
            </div>

            <div className="hidden md:flex items-center gap-8">
              <div className="flex items-center space-x-8">
                {/* Special Lorax Link with active state */}
                <button
                  onClick={toggleLoraxMenu}
                  className={`text-[10px] font-black uppercase tracking-[0.3em] transition-all flex items-center gap-2 ${
                    showLoraxMenu ? 'text-orange-400' : 'text-gray-400 hover:text-white'
                  }`}
                >
                  Lorax {showLoraxMenu ? <X size={12} /> : <div className="w-1.5 h-1.5 rounded-full bg-orange-500 animate-pulse" />}
                </button>

                {navLinks.map((link) => (
                  <a
                    key={link.name}
                    href={link.href}
                    className="text-[10px] font-black uppercase tracking-[0.3em] text-gray-400 hover:text-white transition-colors"
                  >
                    {link.name}
                  </a>
                ))}
              </div>
              <a 
                href="https://apps.apple.com/us/iphone/today"
                target="_blank"
                rel="noopener noreferrer"
                className="bg-gradient-to-r from-blue-600 to-fuchsia-600 hover:from-blue-500 hover:to-fuchsia-500 text-white px-8 py-2.5 rounded-full font-bold transition-all hover:scale-105 active:scale-95 shadow-xl shadow-blue-500/20 text-xs tracking-widest uppercase"
              >
                Join Now
              </a>
            </div>

            <div className="md:hidden flex items-center gap-4">
              <button onClick={toggleLoraxMenu} className={`p-2 rounded-lg ${showLoraxMenu ? 'text-orange-400 bg-orange-400/10' : 'text-gray-400'}`}>
                <Sparkles size={20} />
              </button>
              <button onClick={() => setIsOpen(!isOpen)} className="text-gray-300 hover:text-white p-2">
                {isOpen ? <X size={24} /> : <Menu size={24} />}
              </button>
            </div>
          </div>
        </div>

        {/* Lorax Discovery Mega Menu */}
        {showLoraxMenu && (
          <div className="absolute top-20 left-0 right-0 bg-[#0f0a1e]/95 backdrop-blur-3xl border-b border-white/10 overflow-hidden animate-in slide-in-from-top-4 fade-in duration-500">
            <div className="max-w-7xl mx-auto px-6 py-12 lg:py-16">
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-16 items-center">
                {/* Left Side: Content */}
                <div className="space-y-8">
                  <div>
                    <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-orange-500/10 border border-orange-500/20 text-orange-400 text-[10px] font-black tracking-[0.3em] uppercase mb-6">
                      Natural Harmony
                    </div>
                    <h2 className="text-4xl lg:text-6xl font-black tracking-tighter leading-none text-white mb-6">
                      LORAX <br />
                      <span className="text-transparent bg-clip-text bg-gradient-to-r from-orange-400 via-white to-emerald-400">
                        THE CREASED COSMOS
                      </span>
                    </h2>
                    <p className="text-lg text-gray-400 leading-relaxed font-light italic max-w-lg">
                      "Unless someone like you cares a whole awful lot, nothing is going to get better. It's not."
                    </p>
                  </div>

                  <div className="grid grid-cols-2 gap-4 max-w-md">
                    <div className="p-5 rounded-2xl bg-white/5 border border-white/5 group hover:border-orange-500/30 transition-all">
                      <Wind className="text-orange-400 mb-3" size={20} />
                      <h4 className="text-sm font-bold text-white mb-1">Solar Breath</h4>
                      <p className="text-[9px] text-gray-500 uppercase tracking-widest font-black">Energy Sync Active</p>
                    </div>
                    <div className="p-5 rounded-2xl bg-white/5 border border-white/5 group hover:border-emerald-500/30 transition-all">
                      <Leaf className="text-emerald-400 mb-3" size={20} />
                      <h4 className="text-sm font-bold text-white mb-1">Truffula Fold</h4>
                      <p className="text-[9px] text-gray-500 uppercase tracking-widest font-black">Rare Asset Pattern</p>
                    </div>
                  </div>

                  <button 
                    onClick={() => setShowLoraxMenu(false)}
                    className="group flex items-center gap-3 text-xs font-black uppercase tracking-[0.4em] text-orange-400 hover:text-white transition-all"
                  >
                    Enter Dimension <ArrowRight size={16} className="group-hover:translate-x-2 transition-transform" />
                  </button>
                </div>

                {/* Right Side: Guardian Spirit Visual */}
                <div className="relative flex justify-center lg:justify-end">
                   <div className="relative group w-full max-w-sm">
                      <div className="absolute -inset-1 bg-gradient-to-tr from-orange-500/20 to-emerald-500/20 rounded-[3.5rem] blur-xl opacity-50 group-hover:opacity-100 transition-opacity" />
                      <div className="relative aspect-[4/5] rounded-[3rem] overflow-hidden border border-white/10 bg-[#1a1625] shadow-2xl">
                         <img 
                           src="https://images.unsplash.com/photo-1518531933037-91b2f5f229cc?auto=format&fit=crop&q=80&w=800" 
                           alt="Nebula" 
                           className="w-full h-full object-cover opacity-60 transition-transform duration-1000 group-hover:scale-110"
                         />
                         <div className="absolute inset-0 bg-gradient-to-t from-[#0f0a1e] via-transparent to-orange-500/10" />

                         {/* Centered Sun Orb */}
                         <div className="absolute inset-0 flex items-center justify-center">
                            <div className="w-40 h-40 rounded-full border border-orange-400/20 flex items-center justify-center animate-[pulse_4s_ease-in-out_infinite]">
                               <div className="w-24 h-24 rounded-full border-2 border-orange-400/40 flex items-center justify-center bg-orange-400/5 backdrop-blur-sm">
                                  <Sun size={40} className="text-orange-400 drop-shadow-[0_0_15px_rgba(251,146,60,0.6)]" />
                               </div>
                            </div>
                         </div>

                         {/* Footer Label */}
                         <div className="absolute bottom-6 left-6 right-6 p-5 bg-black/40 backdrop-blur-xl rounded-2xl border border-white/10">
                            <div className="flex items-center gap-4">
                               <div className="w-10 h-10 bg-orange-500/20 rounded-xl flex items-center justify-center">
                                  <Sparkles className="text-orange-400" size={20} />
                               </div>
                               <div>
                                  <div className="text-white text-sm font-bold">Guardian Spirit</div>
                                  <div className="text-[9px] text-gray-500 uppercase tracking-widest font-black">Cosmos Entry #042</div>
                               </div>
                            </div>
                         </div>
                      </div>
                   </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Mobile Menu */}
        {isOpen && (
          <div className="md:hidden bg-[#0f0a1e] border-b border-white/10 py-8 px-6 space-y-6 animate-in slide-in-from-top duration-300">
            <div className="flex flex-col space-y-4">
              <button
                onClick={toggleLoraxMenu}
                className="text-[12px] font-black uppercase tracking-[0.4em] text-orange-400 flex items-center justify-between py-2"
              >
                Lorax Discovery <Sparkles size={16} />
              </button>
              {navLinks.map((link) => (
                <a
                  key={link.name}
                  href={link.href}
                  onClick={() => setIsOpen(false)}
                  className="text-[12px] font-black uppercase tracking-[0.4em] text-gray-400 hover:text-white transition-colors block py-2"
                >
                  {link.name}
                </a>
              ))}
            </div>
            <a 
              href="https://apps.apple.com/us/iphone/today"
              target="_blank"
              rel="noopener noreferrer"
              className="block w-full bg-gradient-to-r from-blue-600 to-fuchsia-600 text-white px-6 py-4 rounded-2xl font-black uppercase tracking-widest text-center text-sm"
            >
              Join Now
            </a>
          </div>
        )}
      </nav>

      {/* Backdrop for Mega Menu */}
      {showLoraxMenu && (
        <div 
          className="fixed inset-0 bg-black/40 z-[90] animate-in fade-in duration-500"
          onClick={() => setShowLoraxMenu(false)}
        />
      )}
    </>
  );
};

export default Navbar;
